// displayWidth 计算字符串的显示宽度（中文等宽字符算 2）
func displayWidth(s string) int {
	width := 0
	for _, r := range s {
		// 判断是否是宽字符（CJK 字符等）
		if r >= 0x4E00 && r <= 0x9FFF { // CJK Unified Ideographs
			width += 2
		} else if r >= 0x3000 && r <= 0x303F { // CJK Symbols and Punctuation
			width += 2
		} else if r >= 0xFF00 && r <= 0xFFEF { // Halfwidth and Fullwidth Forms
			width += 2
		} else if r >= 0x3400 && r <= 0x4DBF { // CJK Unified Ideographs Extension A
			width += 2
		} else if r >= 0x20000 && r <= 0x2A6DF { // CJK Unified Ideographs Extension B
			width += 2
		} else if r >= 0xAC00 && r <= 0xD7AF { // Hangul Syllables
			width += 2
		} else if r >= 0x3040 && r <= 0x309F { // Hiragana
			width += 2
		} else if r >= 0x30A0 && r <= 0x30FF { // Katakana
			width += 2
		} else {
			width += 1
		}
	}
	return width
}

// padRightDisplay 右侧填充空格（考虑显示宽度）
func padRightDisplay(s string, width int) string {
	dw := displayWidth(s)
	if dw >= width {
		return s
	}
	return s + strings.Repeat(" ", width-dw)
}

// truncateByDisplayWidth 按显示宽度截断字符串
func truncateByDisplayWidth(s string, maxWidth int) string {
	width := 0
	for i, r := range s {
		charWidth := 1
		// 判断是否是宽字符（CJK 字符等）
		if r >= 0x4E00 && r <= 0x9FFF { // CJK Unified Ideographs
			charWidth = 2
		} else if r >= 0x3000 && r <= 0x303F { // CJK Symbols and Punctuation
			charWidth = 2
		} else if r >= 0xFF00 && r <= 0xFFEF { // Halfwidth and Fullwidth Forms
			charWidth = 2
		} else if r >= 0x3400 && r <= 0x4DBF { // CJK Unified Ideographs Extension A
			charWidth = 2
		} else if r >= 0x20000 && r <= 0x2A6DF { // CJK Unified Ideographs Extension B
			charWidth = 2
		} else if r >= 0xAC00 && r <= 0xD7AF { // Hangul Syllables
			charWidth = 2
		} else if r >= 0x3040 && r <= 0x309F { // Hiragana
			charWidth = 2
		} else if r >= 0x30A0 && r <= 0x30FF { // Katakana
			charWidth = 2
		}
		if width+charWidth > maxWidth {
			return s[:i]
		}
		width += charWidth
	}
	return s
}
